class Solution {
    public long countGoodIntegers(int n, int k) {
        long count = 0;
        for (int i = 1; i <= 9; i++) {
            for (int j = 0; j < n - 1; j++) {
                for (int l = 0; l <= 9; l++) {
                    for (int m = 0; m < n - 1; m++) {
                        for (int p = 0; p <= 9; p++) {
                            String num = String.valueOf(i) + String.valueOf(j) + String.valueOf(l) + String.valueOf(m) + String.valueOf(p);
                            if (isKPalindrome(num, k) && isValid(num)) {
                                count++;
                            }
                        }
                    }
                }
            }
        }
        return count;
    }
    private boolean isKPalindrome(String num, int k) {
        int left = 0;
        int right = num.length() - 1;
        while (left < right) {
            if (num.charAt(left) != num.charAt(right)) {
                return false;
            }
            left++;
            right--;
        }
        return Integer.parseInt(num) % k == 0;
    }
    private boolean isValid(String num) {
        return !num.startsWith("0") && !num.endsWith("0");
    }
}
